// ── Normalise one Jira item ──────────────────────────────────────────
function normalise(r) {
  const f = r.fields || {};
  const key      = r.key || '';
  const summary  = f.summary || '';
  const created  = f.created || '';
  const status   = f.status?.name   || '';
  const priority = f.priority?.name || '';
  const assignee = f.assignee?.displayName || 'Unassigned';
  const module_  = f.customfield_10196?.value || f.issuetype?.name || 'Other';
  let team = '', commitDate = '';
  for (const [ck, cv] of Object.entries(f)) {
    if (!ck.startsWith('customfield_')) continue;
    if (!team) {
      if (cv && typeof cv === 'object' && !Array.isArray(cv) && cv.name && !cv.value) team = cv.name;
      else if (Array.isArray(cv) && cv[0]?.name) team = cv[0].name;
    }
    if (!commitDate && typeof cv === 'string' && /^\d{4}-\d{2}-\d{2}/.test(cv)) commitDate = cv;
  }
  return { key, summary, status, priority, assignee, created, module: module_, team: team || 'Unassigned', commitDate, _type: r._type };
}

// Merge has 5 inputs: 0=Roadmap, 1=bugs, 2=closed_bugs, 3=features, 4=git
const allItems = $input.all().map(i => i.json);

const rawBugs   = allItems.filter(r => r._type === 'bug');
const rawClosed = allItems.filter(r => r._type === 'closed_bug');
const rawFeats  = allItems.filter(r => r._type === 'feature');
const gitItem   = allItems.find(r => r._type === 'git_commits') || null;

const commitsByTicket    = gitItem?.commitsByTicket   || [];
const allCommitsToday    = gitItem?.allCommitsToday   || [];
const devCommitSummary   = gitItem?.devCommitSummary  || [];
const totalCommits       = gitItem?.totalCommits      || 0;
const totalTicketsTouched = gitItem?.totalTicketsTouched || 0;
const totalReposTouched  = gitItem?.totalReposTouched || 0;
const reposTouched       = gitItem?.reposTouched      || [];
const searchTotal        = gitItem?.searchTotal       || 0;

const bugs   = rawBugs.map(normalise).filter(r => r.key);
const closed = rawClosed.map(normalise).filter(r => r.key);
const feats  = rawFeats.map(normalise).filter(r => r.key);
const allRoadmap = allItems.filter(r => r.Feature && r.Status);
const now = new Date();

// Bug metrics
const closedStatuses = ['Closed','Done','Cancelled','Customer Validation','Duplicate','Do not use','Waiting for customer','On Hold','Pending'];
const openBugs     = bugs.filter(r => r.status && !closedStatuses.includes(r.status));
const criticalBugs = openBugs.filter(r => ['Critical','Highest'].includes(r.priority)).length;
const highBugs     = openBugs.filter(r => r.priority === 'High').length;
const unassigned   = openBugs.filter(r => !r.assignee || r.assignee === 'Unassigned').length;
const closedRecent = closed.length;
const noDate       = openBugs.filter(r => !r.commitDate).length;
const teamCounts = {}, moduleCounts = {};
openBugs.forEach(r => {
  teamCounts[r.team]     = (teamCounts[r.team]     || 0) + 1;
  moduleCounts[r.module] = (moduleCounts[r.module] || 0) + 1;
});
const overdueTickets = openBugs
  .filter(r => r.commitDate && new Date(r.commitDate) < now)
  .slice(0, 5)
  .map(r => ({ key: r.key, summary: r.summary.substring(0, 52), priority: r.priority, team: r.team, assignee: r.assignee, dueDate: r.commitDate }));

// Feature metrics
const openFeatures       = feats.filter(r => r.status && !['Done','Cancelled','Closed'].includes(r.status));
const critFeatures       = openFeatures.filter(r => ['Critical','Highest'].includes(r.priority)).length;
const unassignedFeatures = openFeatures.filter(r => !r.assignee || r.assignee === 'Unassigned').length;
const inProgress         = openFeatures.filter(r => ['Dev In Progress','Testing / QA validation','Awaiting from Partnership','Ready for Development','In Progress'].includes(r.status)).length;
const toDo               = openFeatures.filter(r => ['Scoped(To Do)','Feasibility Analysis','Delivery Planning/ Discussion','To Do','Open','Backlog'].includes(r.status)).length;
const parked             = openFeatures.filter(r => ['Parking lot','On Hold','Parked'].includes(r.status)).length;
const featTeamCounts = {};
openFeatures.forEach(r => { featTeamCounts[r.team] = (featTeamCounts[r.team] || 0) + 1; });
const escalate = openFeatures
  .filter(r => ['Critical','Highest'].includes(r.priority) && r.created && (now - new Date(r.created)) / 86400000 > 100)
  .slice(0, 5)
  .map(r => ({ key: r.key, summary: r.summary.substring(0, 55), team: r.team, assignee: r.assignee, age: Math.floor((now - new Date(r.created)) / 86400000) }));

// Roadmap metrics
const validRoadmap = allRoadmap.filter(r => String(r.Feature).trim() !== '');
const rdDone   = validRoadmap.filter(r => r.Status === 'Done').length;
const rdInProg = validRoadmap.filter(r => r.Status === 'In Progress').length;
const rdToDo   = validRoadmap.filter(r => r.Status === 'To Do').length;
const roadmapRows = validRoadmap.slice(0, 10).map(r => ({ feature: r.Feature, status: r.Status, owner: r.Product || '', fn: r.Function || '', team: r.Team || '' }));

// Per-developer breakdown (Jira + Git merged)
const devMap = {};
const addDev = (assignee, type) => {
  if (!assignee || assignee === 'Unassigned') return;
  if (!devMap[assignee]) devMap[assignee] = { name: assignee, bugs_open: 0, bugs_fixed: 0, features_open: 0 };
  devMap[assignee][type]++;
};
openBugs.forEach(r => addDev(r.assignee, 'bugs_open'));
closed.forEach(r   => addDev(r.assignee, 'bugs_fixed'));
openFeatures.forEach(r => addDev(r.assignee, 'features_open'));
devCommitSummary.forEach(gitDev => {
  const matchName = gitDev.name.toLowerCase();
  let jiraKey = Object.keys(devMap).find(k =>
    k.toLowerCase() === matchName || k.toLowerCase().includes(matchName) || matchName.includes(k.toLowerCase())
  );
  if (!jiraKey) {
    jiraKey = gitDev.name;
    devMap[jiraKey] = { name: gitDev.name, bugs_open: 0, bugs_fixed: 0, features_open: 0 };
  }
  devMap[jiraKey].commits_today   = gitDev.commitCount;
  devMap[jiraKey].tickets_touched = gitDev.uniqueTickets;
  devMap[jiraKey].ticketDetails   = gitDev.ticketDetails || [];
  devMap[jiraKey].repos           = gitDev.repos || [];
});
const developerBreakdown = Object.values(devMap)
  .map(d => ({
    ...d,
    commits_today:   d.commits_today || 0,
    tickets_touched: d.tickets_touched || 0,
    ticketDetails:   d.ticketDetails || [],
    repos:           d.repos || [],
    score: (d.bugs_fixed * 3) + (d.features_open * 2) + d.bugs_open + (d.commits_today || 0)
  }))
  .sort((a, b) => b.score - a.score)
  .slice(0, 12);

// Enrich commitsByTicket with Jira summaries
const jiraSummaryMap = {};
[...bugs, ...closed, ...feats].forEach(r => {
  if (r.key) jiraSummaryMap[r.key.toUpperCase()] = { summary: r.summary, status: r.status, assignee: r.assignee };
});
const enrichedCommits = commitsByTicket.slice(0, 20).map(c => {
  const jira = jiraSummaryMap[c.ticket.toUpperCase()];
  return { ...c, ticketSummary: jira?.summary || '', ticketStatus: jira?.status || '', ticketAssignee: jira?.assignee || '' };
});

const reportDate  = now.toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });
const dbPct       = Math.round(((moduleCounts['DB Query'] || 0) / Math.max(openBugs.length, 1)) * 100);
const noDatePct   = Math.round((noDate / Math.max(openBugs.length, 1)) * 100);
const critPct     = Math.round((criticalBugs / Math.max(openBugs.length, 1)) * 100);
const unFeatPct   = Math.round((unassignedFeatures / Math.max(openFeatures.length, 1)) * 100);
const teamEntries = Object.entries(teamCounts).sort((a, b) => b[1] - a[1]);
const topTeam     = teamEntries[0]?.[0] || 'N/A';
const loadRatio   = teamEntries.length > 1 ? (teamEntries[0][1] / Math.max(teamEntries[1][1], 1)).toFixed(1) : 'N/A';

return [{ json: {
  reportDate, dbPct, noDatePct, critPct, unFeatPct, topTeam, loadRatio,
  bugs:     { total: openBugs.length, critical: criticalBugs, high: highBugs, unassigned, closedRecent, overdueCount: overdueTickets.length, noDate, overdueTickets, teamCounts, moduleCounts },
  features: { total: openFeatures.length, critical: critFeatures, unassigned: unassignedFeatures, inProgress, toDo, parked, teamCounts: featTeamCounts, escalate },
  roadmap:  { done: rdDone, inProgress: rdInProg, toDo: rdToDo, rows: roadmapRows },
  developerBreakdown,
  gitCommits: {
    commitsByTicket: enrichedCommits,
    allCommitsToday: allCommitsToday.slice(0, 30),
    devCommitSummary,
    totalCommits, totalTicketsTouched,
    totalReposTouched, reposTouched, searchTotal
  }
} }];

// ── Create Google Slides via API ─────────────────────────────────────────
// Works on n8n Cloud — no file system needed
// Uses the Google Slides REST API via HTTP Request nodes
// This node builds the full API request payload

const d = $input.first().json;
const { reportDate, dbPct, noDatePct, critPct, unFeatPct, topTeam, loadRatio, bugs, features, roadmap, developerBreakdown, gitCommits } = d;

// ── COLOUR HELPERS ────────────────────────────────────────────────────────
const rgb = (r, g, b) => ({ red: r/255, green: g/255, blue: b/255 });
const NAV    = rgb(30, 45, 78);    // dark navy
const WHITE  = rgb(255,255,255);
const TEAL   = rgb(13,148,136);
const RED    = rgb(220,38,38);
const AMBER  = rgb(217,119,6);
const LGRAY  = rgb(243,246,250);
const SLATE  = rgb(71,85,105);
const MGRAY  = rgb(143,163,184);

// ── SLIDE DIMENSION (16:9 in EMU — 1 inch = 914400 EMU) ─────────────────
const W = 9144000;  // 10 inches
const H = 5143500;  // 5.625 inches
const inch = n => Math.round(n * 914400);

// ── ID GENERATORS ─────────────────────────────────────────────────────────
let idCounter = 1;
const id = () => { const n = String(idCounter++).padStart(4,'0'); return `elem${n}`; };

// ── REQUEST BUILDER HELPERS ───────────────────────────────────────────────
const addSlide = (slideId) => ({
  createSlide: {
    objectId: slideId,
    slideLayoutReference: { predefinedLayout: 'BLANK' }
  }
});

const addRect = (slideId, objId, x, y, w, h, fillColor, strokeColor) => ({
  createShape: {
    objectId: objId,
    shapeType: 'RECTANGLE',
    elementProperties: {
      pageObjectId: slideId,
      size: { width: { magnitude: inch(w), unit: 'EMU' }, height: { magnitude: inch(h), unit: 'EMU' } },
      transform: { scaleX:1, scaleY:1, translateX: inch(x), translateY: inch(y), unit: 'EMU' }
    }
  }
});

const styleRect = (objId, fillColor, strokeColor) => ({
  updateShapeProperties: {
    objectId: objId,
    shapeProperties: {
      shapeBackgroundFill: { solidFill: { color: { rgbColor: fillColor } } },
      outline: strokeColor
        ? { outlineFill: { solidFill: { color: { rgbColor: strokeColor } } }, weight: { magnitude: 12700, unit: 'EMU' } }
        : { propertyState: 'NOT_RENDERED' }
    },
    fields: 'shapeBackgroundFill,outline'
  }
});

const addText = (slideId, objId, x, y, w, h, text, fontSize, color, bold, hAlign, vAlign) => {
  const safeText = String(text == null ? '' : text);
  const ops = [{
    createShape: {
      objectId: objId,
      shapeType: 'TEXT_BOX',
      elementProperties: {
        pageObjectId: slideId,
        size: { width: { magnitude: inch(w), unit: 'EMU' }, height: { magnitude: inch(h), unit: 'EMU' } },
        transform: { scaleX:1, scaleY:1, translateX: inch(x), translateY: inch(y), unit: 'EMU' }
      }
    }
  }];
  if (safeText.length > 0) {
    ops.push({ insertText: { objectId: objId, text: safeText } });
    ops.push({ updateTextStyle: { objectId: objId, style: { fontSize: { magnitude: fontSize, unit: 'PT' }, foregroundColor: { opaqueColor: { rgbColor: color } }, bold: !!bold, fontFamily: 'Calibri' }, fields: 'fontSize,foregroundColor,bold,fontFamily' } });
    ops.push({ updateParagraphStyle: { objectId: objId, style: { alignment: hAlign || 'START', spaceAbove: { magnitude: 0, unit: 'PT' }, spaceBelow: { magnitude: 0, unit: 'PT' } }, fields: 'alignment,spaceAbove,spaceBelow' } });
  }
  return ops;
};

const setBg = (slideId, color) => ({
  updatePageProperties: {
    objectId: slideId,
    pageProperties: { pageBackgroundFill: { solidFill: { color: { rgbColor: color } } } },
    fields: 'pageBackgroundFill'
  }
});

// Convenience: add a coloured rectangle + label
const kpiCard = (slideId, x, y, w, h, value, label, sub, valColor) => {
  const bgId = id(), valId = id(), lblId = id(), subId = id();
  return [
    addRect(slideId, bgId, x, y, w, h, WHITE),
    styleRect(bgId, WHITE, MGRAY),
    ...addText(slideId, valId, x, y+0.06, w, h*0.52, value, 26, valColor||NAV, true, 'CENTER'),
    ...addText(slideId, lblId, x, y+h*0.56, w, h*0.24, label, 9, SLATE, true, 'CENTER'),
    ...(sub ? addText(slideId, subId, x, y+h*0.78, w, h*0.2, sub, 7.5, MGRAY, false, 'CENTER') : [])
  ];
};

// ── BUILD REQUESTS ARRAY ──────────────────────────────────────────────────
const requests = [];

// Delete the blank slide Google auto-creates on presentation creation
requests.push({ deleteObject: { objectId: 'p' } });

// ════════════════════════════════════════════════════════════════════════
// SLIDE 1 — COVER
// ════════════════════════════════════════════════════════════════════════
const s1 = 'slide_cover';
requests.push(addSlide(s1));
requests.push(setBg(s1, NAV));

// Teal left accent strip
const s1_strip = id();
requests.push(addRect(s1, s1_strip, 0, 0, 0.15, 5.625, TEAL));
requests.push(styleRect(s1_strip, TEAL));

// Dark right panel
const s1_panel = id();
const panelBg = rgb(22,39,64);
requests.push(addRect(s1, s1_panel, 6.2, 0, 3.8, 5.625, panelBg));
requests.push(styleRect(s1_panel, panelBg));

// Teal accent bottom right
const s1_teal = id();
requests.push(addRect(s1, s1_teal, 8.4, 3.8, 1.75, 1.825, TEAL));
requests.push(styleRect(s1_teal, TEAL));

// Title text
requests.push(...addText(s1, id(), 0.4, 1.0, 5.5, 1.0, 'Engineering', 48, WHITE, true, 'START'));
requests.push(...addText(s1, id(), 0.4, 1.9, 5.5, 0.8, 'Executive Dashboard', 34, rgb(214,228,247), false, 'START'));
requests.push(...addText(s1, id(), 0.4, 3.1, 5.0, 0.35, 'Sprouts — Platform Engineering', 13, rgb(214,228,247), false, 'START'));
requests.push(...addText(s1, id(), 0.4, 3.5, 5.0, 0.28, `${reportDate}  ·  Confidential`, 11, MGRAY, false, 'START'));

// Right panel stats
const coverStats = [
  { val: String(bugs.total),    lbl: 'Open Bugs/Support',         col: RED  },
  { val: String(features.total),lbl: 'Feature Requests',  col: AMBER},
  { val: String(roadmap.done),  lbl: 'Shipped This Month', col: TEAL }
];
coverStats.forEach((s, i) => {
  const cy = 1.2 + i * 1.3;
  requests.push(...addText(s1, id(), 6.4, cy, 1.2, 0.8, s.val, 40, s.col, true, 'CENTER'));
  requests.push(...addText(s1, id(), 7.6, cy+0.18, 2.1, 0.45, s.lbl, 12, rgb(214,228,247), false, 'START'));
});

// ════════════════════════════════════════════════════════════════════════
// SLIDE 2 — EXECUTIVE SUMMARY
// ════════════════════════════════════════════════════════════════════════
const s2 = 'slide_exec';
requests.push(addSlide(s2));
requests.push(setBg(s2, LGRAY));

// Teal top bar
const s2_bar = id();
requests.push(addRect(s2, s2_bar, 0, 0, 10, 0.08, TEAL));
requests.push(styleRect(s2_bar, TEAL));

requests.push(...addText(s2, id(), 0.35, 0.12, 9, 0.5, 'Executive Summary', 24, NAV, true, 'START'));

const summCols = [
  { x:0.25, title:'Critical Risks', color: RED, items: [
    `${bugs.total} open bugs/support — ${critPct}% critical`,
    `${noDatePct}% have no delivery date`,
    `DB Query = ${dbPct}% of bug queue`,
    `${topTeam} ${loadRatio}× team load imbalance`,
    `${bugs.overdueCount} ticket(s) past committed date`
  ]},
  { x:3.55, title:'Immediate Actions', color: AMBER, items: [
    `Assign ${bugs.unassigned} unowned bugs now`,
    `Assign ${features.unassigned} unowned features`,
    `Mandate delivery dates (${noDatePct}% missing)`,
    'Weekly Critical review cadence',
    'Root-cause sprint for DB Query'
  ]},
  { x:6.85, title:'Positive Signals', color: TEAL, items: [
    `${bugs.closedRecent} bugs closed in 7 days`,
    `${roadmap.done} features shipped on time`,
    `${roadmap.inProgress} features in flight`,
    'Trend Score & AI Discover progressing',
    'Strong closure velocity'
  ]}
];

summCols.forEach(col => {
  const bgId = id(), hdrId = id();
  // card background
  requests.push(addRect(s2, bgId, col.x, 0.78, 3.1, 4.6, WHITE));
  requests.push(styleRect(bgId, WHITE, MGRAY));
  // coloured header
  const hdrBgId = id();
  requests.push(addRect(s2, hdrBgId, col.x, 0.78, 3.1, 0.42, col.color));
  requests.push(styleRect(hdrBgId, col.color));
  requests.push(...addText(s2, id(), col.x+0.1, 0.8, 2.9, 0.38, col.title, 10, WHITE, true, 'START'));
  // bullet items
  col.items.forEach((item, i) => {
    const dotId = id();
    requests.push(addRect(s2, dotId, col.x+0.15, 1.34+i*0.6+0.1, 0.08, 0.08, col.color));
    requests.push(styleRect(dotId, col.color));
    requests.push(...addText(s2, id(), col.x+0.3, 1.34+i*0.6, 2.7, 0.52, item, 9, rgb(45,62,84), false, 'START'));
  });
});

// ════════════════════════════════════════════════════════════════════════
// SLIDE 3 — CSI BUG QUEUE
// ════════════════════════════════════════════════════════════════════════
const s3 = 'slide_bugs';
requests.push(addSlide(s3));
requests.push(setBg(s3, LGRAY));
const s3_bar = id();
requests.push(addRect(s3, s3_bar, 0, 0, 10, 0.08, TEAL));
requests.push(styleRect(s3_bar, TEAL));
requests.push(...addText(s3, id(), 0.35, 0.12, 9, 0.5, 'CSI Bug / Support Queue', 24, NAV, true, 'START'));

// KPI cards row
const bugKpis = [
  { val: String(bugs.total),       lbl:'Total Open',     sub:'Active queue',      col:NAV  },
  { val: String(bugs.critical),    lbl:'Critical',       sub:`${critPct}% of queue`, col:RED  },
  { val: String(bugs.high),        lbl:'High Priority',  sub:'',                  col:AMBER},
  { val: String(bugs.unassigned),  lbl:'Unassigned',     sub:'No owner',          col:RED  },
  { val: String(bugs.closedRecent),lbl:'Closed (7d)',    sub:'Velocity',          col:TEAL },
  { val: String(bugs.overdueCount),lbl:'Overdue',        sub:'Past commit date',  col:RED  },
];
bugKpis.forEach((k, i) => {
  requests.push(...kpiCard(s3, 0.2+i*1.61, 0.72, 1.46, 0.92, k.val, k.lbl, k.sub, k.col));
});

// Team bars — left panel
const s3_lbg = id();
requests.push(addRect(s3, s3_lbg, 0.2, 1.76, 4.6, 3.0, WHITE));
requests.push(styleRect(s3_lbg, WHITE, MGRAY));
requests.push(...addText(s3, id(), 0.35, 1.84, 4.0, 0.28, 'Tickets by team', 11, NAV, true, 'START'));

const teamEntries = Object.entries(bugs.teamCounts).sort((a,b)=>b[1]-a[1]).slice(0,6);
const maxTeam = Math.max(...teamEntries.map(([,v])=>v), 1);
const barColors = [RED, rgb(59,130,246), AMBER, TEAL, MGRAY, MGRAY];
teamEntries.forEach(([team, count], i) => {
  const barW = 2.5 * (count / maxTeam);
  const by = 2.2 + i * 0.38;
  requests.push(...addText(s3, id(), 0.3, by, 1.7, 0.3, team, 8.5, SLATE, false, 'START'));
  const trackId = id();
  requests.push(addRect(s3, trackId, 2.05, by+0.06, 2.5, 0.18, LGRAY));
  requests.push(styleRect(trackId, LGRAY));
  if (barW > 0) {
    const fillId = id();
    requests.push(addRect(s3, fillId, 2.05, by+0.06, barW, 0.18, barColors[i]||MGRAY));
    requests.push(styleRect(fillId, barColors[i]||MGRAY));
  }
  requests.push(...addText(s3, id(), 4.62, by, 0.3, 0.3, String(count), 8.5, NAV, true, 'START'));
});

// Module bars — right panel
const s3_rbg = id();
requests.push(addRect(s3, s3_rbg, 5.1, 1.76, 4.7, 3.0, WHITE));
requests.push(styleRect(s3_rbg, WHITE, MGRAY));
requests.push(...addText(s3, id(), 5.25, 1.84, 4.0, 0.28, 'Tickets by module', 11, NAV, true, 'START'));

const modEntries = Object.entries(bugs.moduleCounts).sort((a,b)=>b[1]-a[1]).slice(0,5);
const maxMod = Math.max(...modEntries.map(([,v])=>v), 1);
modEntries.forEach(([mod, count], i) => {
  const barW = 2.6 * (count / maxMod);
  const by = 2.2 + i * 0.38;
  requests.push(...addText(s3, id(), 5.2, by, 1.8, 0.3, mod, 8.5, SLATE, false, 'START'));
  const trackId = id();
  requests.push(addRect(s3, trackId, 7.08, by+0.06, 2.6, 0.18, LGRAY));
  requests.push(styleRect(trackId, LGRAY));
  if (barW > 0) {
    const fillId = id();
    requests.push(addRect(s3, fillId, 7.08, by+0.06, barW, 0.18, barColors[i]||MGRAY));
    requests.push(styleRect(fillId, barColors[i]||MGRAY));
  }
  requests.push(...addText(s3, id(), 9.75, by, 0.3, 0.3, String(count), 8.5, NAV, true, 'START'));
});

// Warning banner
const s3_warnBg = id();
requests.push(addRect(s3, s3_warnBg, 0.2, 4.84, 9.6, 0.26, rgb(254,242,242)));
requests.push(styleRect(s3_warnBg, rgb(254,242,242), RED));
requests.push(...addText(s3, id(), 0.35, 4.84, 9.3, 0.26, `⚠  DB Query = ${dbPct}% of all bugs. ${topTeam} carries ${loadRatio}× the load of next team. Root-cause analysis required.`, 8, RED, false, 'START'));

// ════════════════════════════════════════════════════════════════════════
// SLIDE 4 — FEATURE REQUESTS
// ════════════════════════════════════════════════════════════════════════
const s4 = 'slide_features';
requests.push(addSlide(s4));
requests.push(setBg(s4, LGRAY));
const s4_bar = id();
requests.push(addRect(s4, s4_bar, 0, 0, 10, 0.08, TEAL));
requests.push(styleRect(s4_bar, TEAL));
requests.push(...addText(s4, id(), 0.35, 0.12, 9, 0.5, 'Feature Request Queue', 24, NAV, true, 'START'));

const featKpis = [
  { val:String(features.total),      lbl:'Total Open',   sub:'',                     col:NAV  },
  { val:String(features.critical),   lbl:'Critical',     sub:`${critPct}% of queue`, col:RED  },
