// ── Parse GitHub commits — handles BOTH response shapes ────────────────
// Shape A (Search API): single item per input = { total_count, items: [...] }
// Shape B (List API):   one item per commit   = { sha, commit: {...}, ... }
// We detect which shape each input item is and normalise to a flat array.

const allInputs = $input.all().map(i => i.json);
const now = new Date();
const oneDayAgo = new Date(now - 24 * 60 * 60 * 1000);
const ticketRe = /(?:CSI|SPROUT)-\d+/gi;

// Normalise: flatten regardless of which API shape arrived
const seen = new Set();
const uniqueItems = [];
allInputs.forEach(input => {
  // Shape A — Search API: input has .items array
  if (Array.isArray(input.items)) {
    input.items.forEach(item => {
      if (item.sha && !seen.has(item.sha)) {
        seen.add(item.sha);
        uniqueItems.push(item);
      }
    });
  }
  // Shape B — List API: input IS the commit object directly
  else if (input.sha && input.commit) {
    if (!seen.has(input.sha)) {
      seen.add(input.sha);
      // List API doesn't have item.repository — inject from url
      if (!input.repository) {
        const match = (input.url || input.html_url || '').match(/repos\/[^/]+\/([^/]+)/);
        input.repository = { name: match ? match[1] : 'unknown-repo' };
      }
      uniqueItems.push(input);
    }
  }
});

// Parse each commit into a flat object
const parsedCommits = uniqueItems.map(item => {
  const commit     = item.commit     || {};
  const author     = commit.author   || {};
  const committer  = commit.committer || {};
  const message    = commit.message  || '';
  const sha        = item.sha        || '';
  const url        = item.html_url   || '';
  const repo       = item.repository?.name || 'unknown-repo';
  const commitDate = new Date(committer.date || author.date || now);
  const authorName  = author.name       || item.author?.login  || 'Unknown';
  const authorLogin = item.author?.login || '';
  const ticketMatches = [...message.matchAll(ticketRe)].map(m => m[0].toUpperCase());
  const tickets = [...new Set(ticketMatches)];
  const firstLine = message.split('\n')[0].trim();
  return { sha, url, message: firstLine, authorName, authorLogin, commitDate, tickets, repo };
});

// Only commits within last 24 hours that reference a ticket
const todayCommits = parsedCommits.filter(c =>
  c.commitDate >= oneDayAgo && c.tickets.length > 0
);

// Most recent commit per ticket (for display card)
const ticketMap = {};
todayCommits.forEach(c => {
  c.tickets.forEach(ticket => {
    const ex = ticketMap[ticket];
    if (!ex || c.commitDate > new Date(ex.commitDate)) {
      ticketMap[ticket] = {
        ticket, message: c.message, author: c.authorName,
        authorLogin: c.authorLogin, commitDate: c.commitDate.toISOString(),
        url: c.url, sha: c.sha.substring(0, 7), repo: c.repo
      };
    }
  });
});
const commitsByTicket = Object.values(ticketMap)
  .sort((a, b) => new Date(b.commitDate) - new Date(a.commitDate));

// All today's commits flat list
const allCommitsToday = todayCommits
  .map(c => ({
    ticket: c.tickets[0], allTickets: c.tickets,
    message: c.message, author: c.authorName, authorLogin: c.authorLogin,
    commitDate: c.commitDate.toISOString(), url: c.url,
    sha: c.sha.substring(0, 7), repo: c.repo
  }))
  .sort((a, b) => new Date(b.commitDate) - new Date(a.commitDate));

// Per-developer summary
const devCommitMap = {};
allCommitsToday.forEach(c => {
  const dev = c.author;
  if (!devCommitMap[dev]) devCommitMap[dev] = {
    name: dev, login: c.authorLogin,
    commitCount: 0, tickets: new Set(), repos: new Set(), ticketDetails: {}
  };
  devCommitMap[dev].commitCount++;
  devCommitMap[dev].tickets.add(c.ticket);
  devCommitMap[dev].repos.add(c.repo);
  devCommitMap[dev].ticketDetails[c.ticket] = (devCommitMap[dev].ticketDetails[c.ticket] || 0) + 1;
});
const devCommitSummary = Object.values(devCommitMap).map(d => ({
  name: d.name, login: d.login,
  commitCount: d.commitCount,
  uniqueTickets: d.tickets.size,
  repos: [...d.repos],
  ticketDetails: Object.entries(d.ticketDetails)
    .map(([ticket, count]) => ({ ticket, count }))
    .sort((a, b) => b.count - a.count)
})).sort((a, b) => b.commitCount - a.commitCount);

const reposTouched = [...new Set(allCommitsToday.map(c => c.repo))];

return [{ json: {
  _type: 'git_commits',
  commitsByTicket, allCommitsToday, devCommitSummary,
  totalCommits: allCommitsToday.length,
  totalTicketsTouched: commitsByTicket.length,
  totalReposTouched: reposTouched.length,
  reposTouched,
  searchTotal: uniqueItems.length
} }];
